#include<bits/stdc++.h>
using namespace std;
int a[1000];
bool cmp(int x, int y){
    return x > y;
}
int main()
{
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= n * m; i++)cin >> a[i];
    int x = a[1];
    sort(a + 1, a + n * m + 1, cmp);
    for(int i = 1; i <= n * m; i++){
        if(a[i] == x){
            x = i ;
            break;
        }
    }
    int lie = x / n, hang = x % n;
    if(hang)lie++;
    else hang = n;
    if(lie & 1){
        cout << lie << " " << hang;
    }else {
        cout << lie << " " << n - hang + 1;
    }
}
